patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..158dd684bb66 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -632,7 +632,7 @@ static void breakSelfRecursivePHI(const Use *U, const PHINode *PHI,
   }
 }

-static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
+static bool isKnownNonZeroFromAssume(const Value *V, const APInt &DemandedElts, const SimplifyQuery &Q, unsigned Depth) {
   // Use of assumptions is context-sensitive. If we don't have a context, we
   // cannot use them!
   if (!Q.AC || !Q.CxtI)
@@ -672,7 +672,7 @@ static bool isKnownNonZeroFromAssume(const Value *V, const SimplifyQuery &Q) {
     if (!match(I->getArgOperand(0), m_c_ICmp(Pred, m_V, m_Value(RHS))))
       continue;

-    if (cmpExcludesZero(Pred, RHS) && isValidAssumeForContext(I, Q.CxtI, Q.DT))
+    if ((cmpExcludesZero(Pred, RHS) || (Pred == ICmpInst::ICMP_EQ && isKnownNonZero(RHS, DemandedElts, Q, Depth))) && isValidAssumeForContext(I, Q.CxtI, Q.DT))
       return true;
   }

@@ -3519,7 +3519,7 @@ bool isKnownNonZero(const Value *V, const APInt &DemandedElts,
         return true;
     }

-  if (!isa<Constant>(V) && isKnownNonZeroFromAssume(V, Q))
+  if (!isa<Constant>(V) && isKnownNonZeroFromAssume(V, DemandedElts, Q, Depth))
     return true;

   // Some of the tests below are recursive, so bail out if we hit the limit.
@@ -3936,6 +3936,13 @@ static bool isKnownNonEqual(const Value *V1, const Value *V2,
       isModifyingBinopOfNonZero(V2, V1, DemandedElts, Q, Depth))
     return true;

+  // V1 != V2 if V1 - V2 is known non-zero.
+  if (V1->getType()->isIntOrIntVectorTy()) {
+    unsigned BitWidth = getBitWidth(V1->getType()->getScalarType(), Q.DL);
+    if (isNonZeroSub(DemandedElts, Q, BitWidth, const_cast<Value *>(V1), const_cast<Value *>(V2), Depth + 1))
+      return true;
+  }
+
   if (isNonEqualMul(V1, V2, DemandedElts, Q, Depth) ||
       isNonEqualMul(V2, V1, DemandedElts, Q, Depth))
     return true;

